import{_ as n,o as t,c as i,ag as r}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Abrechnung & Tarife","description":"","frontmatter":{},"headers":[],"relativePath":"de/settings/billing.md","filePath":"de/settings/billing.md"}'),a={name:"de/settings/billing.md"};function l(d,e,u,o,s,g){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="abrechnung-tarife" tabindex="-1">Abrechnung &amp; Tarife <a class="header-anchor" href="#abrechnung-tarife" aria-label="Permalink to &quot;Abrechnung &amp; Tarife&quot;">​</a></h1><p>Verwalten Sie Ihr MyCompanyDesk-Abonnement, sehen Sie Ihre Nutzung ein und führen Sie ein Upgrade Ihres Tarifs durch.</p><h2 id="tarife" tabindex="-1">Tarife <a class="header-anchor" href="#tarife" aria-label="Permalink to &quot;Tarife&quot;">​</a></h2><p>MyCompanyDesk bietet drei Tarife:</p><h3 id="free" tabindex="-1">Free <a class="header-anchor" href="#free" aria-label="Permalink to &quot;Free&quot;">​</a></h3><p>Kostenlos starten:</p><ul><li>Begrenzte Rechnungen und Kunden</li><li>Grundlegende Ausgabenverfolgung</li><li>Grundlegende Berichte</li><li>1 Benutzer</li><li>Community-Support</li></ul><h3 id="pro" tabindex="-1">Pro <a class="header-anchor" href="#pro" aria-label="Permalink to &quot;Pro&quot;">​</a></h3><p>Für wachsende Unternehmen:</p><ul><li>Unbegrenzte Rechnungen und Kunden</li><li>Vollständige Ausgabenverfolgung mit Belegscanner</li><li>KI-Vorschläge</li><li>Individuelles PDF-Branding</li><li>CSV-Export</li><li>Bis zu 5 Teammitglieder</li><li>E-Mail-Support</li></ul><h3 id="business" tabindex="-1">Business <a class="header-anchor" href="#business" aria-label="Permalink to &quot;Business&quot;">​</a></h3><p>Für Teams und skalierenden Betrieb:</p><ul><li>Alles aus Pro</li><li>Unbegrenzte Teammitglieder</li><li>API-Zugang</li><li>Prioritäts-Support</li><li>Erweiterte Integrationen</li></ul><p>Tarife sind in <strong>monatlichen</strong> und <strong>jährlichen</strong> Abrechnungsintervallen verfügbar. Jahrestarife beinhalten einen Rabatt.</p><h2 id="abonnement-verwalten" tabindex="-1">Abonnement verwalten <a class="header-anchor" href="#abonnement-verwalten" aria-label="Permalink to &quot;Abonnement verwalten&quot;">​</a></h2><h3 id="upgrade" tabindex="-1">Upgrade <a class="header-anchor" href="#upgrade" aria-label="Permalink to &quot;Upgrade&quot;">​</a></h3><ol><li>Gehen Sie zu <strong>Einstellungen &gt; Abrechnung</strong></li><li>Klicken Sie auf <strong>Upgrade</strong> beim gewünschten Tarif</li><li>Schließen Sie die Zahlung über Stripe ab</li><li>Funktionen werden sofort aktiviert</li></ol><h3 id="downgrade" tabindex="-1">Downgrade <a class="header-anchor" href="#downgrade" aria-label="Permalink to &quot;Downgrade&quot;">​</a></h3><ol><li>Gehen Sie zu <strong>Einstellungen &gt; Abrechnung</strong></li><li>Klicken Sie auf <strong>Tarif ändern</strong></li><li>Wählen Sie den niedrigeren Tarif</li><li>Änderungen treten am Ende der aktuellen Abrechnungsperiode in Kraft</li></ol><h3 id="kundigung" tabindex="-1">Kündigung <a class="header-anchor" href="#kundigung" aria-label="Permalink to &quot;Kündigung&quot;">​</a></h3><ol><li>Gehen Sie zu <strong>Einstellungen &gt; Abrechnung</strong></li><li>Klicken Sie auf <strong>Abonnement verwalten</strong>, um das Stripe-Abrechnungsportal zu öffnen</li><li>Kündigen Sie Ihr Abonnement</li><li>Sie behalten den Zugang bis zum Ende des bezahlten Zeitraums</li></ol><h2 id="nutzungsverfolgung" tabindex="-1">Nutzungsverfolgung <a class="header-anchor" href="#nutzungsverfolgung" aria-label="Permalink to &quot;Nutzungsverfolgung&quot;">​</a></h2><p>Sehen Sie Ihre aktuelle Nutzung auf der Abrechnungsseite:</p><ul><li><strong>Erstellte Rechnungen</strong> in diesem Monat</li><li><strong>Kunden</strong> in Ihrem Arbeitsbereich</li><li><strong>Teammitglieder</strong> aktiv</li><li><strong>API-Aufrufe</strong> (Business-Tarif)</li></ul><p>Die Nutzung wird monatlich zurückgesetzt. Wenn Sie sich einem Limit nähern, sehen Sie eine Benachrichtigung mit Upgrade-Vorschlag.</p><h2 id="zahlungsmethoden" tabindex="-1">Zahlungsmethoden <a class="header-anchor" href="#zahlungsmethoden" aria-label="Permalink to &quot;Zahlungsmethoden&quot;">​</a></h2><p>Zahlungen werden sicher über <strong>Stripe</strong> abgewickelt. Akzeptierte Methoden:</p><ul><li>Kreditkarte (Visa, Mastercard, Amex)</li><li>Debitkarte</li><li>SEPA-Lastschrift (EU)</li></ul><p>Verwalten Sie Ihre Zahlungsmethode im Stripe-Abrechnungsportal.</p><h2 id="abrechnungsportal" tabindex="-1">Abrechnungsportal <a class="header-anchor" href="#abrechnungsportal" aria-label="Permalink to &quot;Abrechnungsportal&quot;">​</a></h2><p>Klicken Sie auf <strong>Abonnement verwalten</strong>, um auf das Stripe-Abrechnungsportal zuzugreifen, wo Sie:</p><ul><li>Zahlungsmethode aktualisieren</li><li>Rechnungsverlauf einsehen</li><li>Belege herunterladen</li><li>Rechnungsadresse ändern</li></ul><h2 id="funktionsberechtigungen" tabindex="-1">Funktionsberechtigungen <a class="header-anchor" href="#funktionsberechtigungen" aria-label="Permalink to &quot;Funktionsberechtigungen&quot;">​</a></h2><p>Einige Funktionen sind an den Tarif gebunden:</p><table tabindex="0"><thead><tr><th>Funktion</th><th>Free</th><th>Pro</th><th>Business</th></tr></thead><tbody><tr><td>Individuelles Branding</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>CSV-Export</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>Belegscanner</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>KI-Vorschläge</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>Textprüfung</td><td>-</td><td>Ja</td><td>Ja</td></tr><tr><td>API-Zugang</td><td>-</td><td>-</td><td>Ja</td></tr></tbody></table><p>Der Versuch, eine tarifgebundene Funktion in einem niedrigeren Tarif zu nutzen, zeigt eine Upgrade-Aufforderung.</p>',36)])])}const b=n(a,[["render",l]]);export{c as __pageData,b as default};
